# chatcli Remote Agent — 一键部署（不依赖 GitHub）
$ErrorActionPreference = "Stop"
Write-Host "=== chatcli Remote Agent ===" -ForegroundColor Cyan

# Check Python (Windows uses 'py' launcher)
if (-not (Get-Command py -ErrorAction SilentlyContinue)) {
    Write-Host "请先装 Python 3.10+: https://python.org" -ForegroundColor Red; exit 1
}
Write-Host "Python: $(py -3 --version)" -ForegroundColor Green

Write-Host "安装依赖..." -ForegroundColor Yellow
py -3 -m pip install fastapi uvicorn python-multipart --quiet
Write-Host "完成" -ForegroundColor Green

Write-Host "部署 Agent..." -ForegroundColor Yellow
$b64 = @'

'@
$b64 = ($b64 -replace '\s','').Trim()
$pyCode = [Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($b64))
Set-Content -Path C:\chatcli_agent.py -Value $pyCode -Encoding UTF8

# Generate random token
$chars = (48..57) + (65..90) + (97..122)
$token = -join ($chars | Get-Random -Count 48 | ForEach { [char]$_ })
[Environment]::SetEnvironmentVariable("CHATCLI_GUEST_AGENT_TOKEN", $token, "Machine")
$env:CHATCLI_GUEST_AGENT_TOKEN = $token

mkdir C:\analysis\cases, C:\analysis\outbox -Force | Out-Null
New-NetFirewallRule -DisplayName "chatcli Agent" -Direction Inbound -Protocol TCP -LocalPort 8443 -Action Allow -ErrorAction SilentlyContinue | Out-Null

Write-Host "" -ForegroundColor Green
Write-Host "=== 部署完成 ===" -ForegroundColor Cyan
Write-Host "Token: $token" -ForegroundColor Yellow
Write-Host ""
Write-Host "chatcli 侧配置:" -ForegroundColor White
Write-Host "  remote:" -ForegroundColor Gray
Write-Host "    enabled: true" -ForegroundColor Gray
Write-Host "    base_url: http://<IP>:8443" -ForegroundColor Gray
Write-Host "    guest_agent_token: $token" -ForegroundColor Gray
Write-Host ""
py -3 C:\chatcli_agent.py --host 0.0.0.0 --port 8443
